INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' À primeira alteração ao Decreto-Lei n.º 72/2004, de 25 de março, que transpõe para a ordem jurídica nacional a Diretiva 2003/40/CE da Comissão, de 16 de maio de 2003, que estabelece a lista, os limites de concentração e as menções constantes do rótulo para os constituintes das águas minerais naturais, bem como as condições de utilização de ar enriquecido em ozono para o tratamento das águas minerais naturais e das águas de nascente;
  zz) À segunda alteração ao Decreto-Lei n.º 213/2004, de 23 de agosto, alterado pelo Decreto-Lei n.º 176/2015, de 25 de agosto, que, no uso da autorização legislativa concedida pela Lei n.º 7/2004, de 5 de março, estabelece o regime de infrações relativas ao incumprimento da disciplina legal aplicável à vinha, à produção, ao comércio, à transformação e ao trânsito dos vinhos e dos outros produtos vitivinícolas e às atividades desenvolvidas neste setor;
